INSERT INTO areas (id, name, description, sort_order) VALUES
  (1, 'Finance & Unit Economics', 'Revenue models, pricing, cash flow, financial planning, and unit economics that drive P&L performance.', 1),
  (2, 'Product & Offering', 'Product strategy, roadmap, development lifecycle, customer feedback loops, and competitive positioning.', 2),
  (3, 'Go-To-Market & Sales', 'Sales process, pipeline management, customer acquisition, channel strategy, and revenue generation.', 3),
  (4, 'Marketing & Brand', 'Brand positioning, demand generation, content strategy, marketing operations, and market awareness.', 4),
  (5, 'People & Organization', 'Talent acquisition, culture, performance management, organizational design, and leadership development.', 5),
  (6, 'Technology & Infrastructure', 'Architecture, engineering practices, security, scalability, and technical debt management.', 6),
  (7, 'Delivery & Operations', 'Project delivery, operational efficiency, quality assurance, process optimization, and supply chain.', 7),
  (8, 'Governance & Leadership', 'Strategic planning, decision-making frameworks, board management, risk governance, and executive alignment.', 8);
INSERT INTO practices (id, area_id, name, description, version, sort_order) VALUES
  (1, 1, 'Revenue Model Clarity', 'Clear articulation of how the business generates revenue, including pricing tiers, monetization strategy, and value exchange.', '1.0', 1),
  (2, 1, 'Unit Economics Tracking', 'Measurement and optimization of per-unit profitability including CAC, LTV, gross margin, and contribution margin.', '1.0', 2),
  (3, 1, 'Cash Flow Management', 'Forecasting, monitoring, and optimizing cash inflows and outflows to ensure operational continuity.', '1.0', 3),
  (4, 1, 'Financial Planning & Analysis', 'Budgeting, forecasting, variance analysis, and scenario planning to guide strategic decisions.', '1.0', 4),
  (5, 1, 'Pricing Strategy', 'Data-driven pricing decisions aligned with market positioning, cost structure, and customer willingness to pay.', '1.0', 5),
  (6, 1, 'Cost Structure Optimization', 'Systematic identification and reduction of unnecessary costs while preserving value delivery capacity.', '1.0', 6),
  (7, 1, 'Revenue Diversification', 'Reducing concentration risk by developing multiple revenue streams and customer segments.', '1.0', 7),
  (8, 1, 'Financial Reporting & Controls', 'Accurate, timely financial reporting with appropriate internal controls and audit readiness.', '1.0', 8),
  (9, 1, 'Capital Allocation Discipline', 'Structured approach to investing capital across initiatives based on expected returns and strategic fit.', '1.0', 9),
  (10, 1, 'Investor & Stakeholder Communication', 'Transparent, regular communication of financial performance and strategy to investors and stakeholders.', '1.0', 10),
  (11, 2, 'Product Vision & Strategy', 'A compelling, documented product vision that aligns the team and guides roadmap decisions.', '1.0', 1),
  (12, 2, 'Customer Discovery Process', 'Systematic methods for understanding customer needs, pain points, and jobs-to-be-done.', '1.0', 2),
  (13, 2, 'Product Roadmap Management', 'Prioritized, outcome-driven roadmap that balances customer needs, business goals, and technical debt.', '1.0', 3),
  (14, 2, 'Feature Prioritization Framework', 'Consistent, transparent methodology for deciding what to build next based on impact and effort.', '1.0', 4),
  (15, 2, 'Product-Market Fit Measurement', 'Quantitative and qualitative signals confirming the product solves a real problem for a defined market.', '1.0', 5),
  (16, 2, 'User Experience Design', 'Intentional design of user interactions that reduce friction and increase engagement and satisfaction.', '1.0', 6),
  (17, 2, 'Product Analytics & Instrumentation', 'Data collection and analysis of product usage patterns to inform decisions and measure outcomes.', '1.0', 7),
  (18, 2, 'Competitive Intelligence', 'Ongoing monitoring and analysis of competitor offerings, positioning, and market movements.', '1.0', 8),
  (19, 2, 'Product Feedback Loop', 'Structured collection, synthesis, and action on customer feedback across all touchpoints.', '1.0', 9),
  (20, 2, 'Product Quality Standards', 'Defined quality benchmarks, acceptance criteria, and release gates that protect customer experience.', '1.0', 10),
  (21, 2, 'Innovation Pipeline', 'Systematic approach to exploring new product opportunities beyond the current roadmap.', '1.0', 11),
  (22, 3, 'Ideal Customer Profile Definition', 'Clear, data-backed definition of the target customer including firmographics, behavior, and buying signals.', '1.0', 1),
  (23, 3, 'Sales Process & Methodology', 'Documented, repeatable sales process from lead qualification through close with defined stages and criteria.', '1.0', 2),
  (24, 3, 'Pipeline Management & Forecasting', 'Accurate visibility into sales pipeline health, velocity, and revenue forecasting.', '1.0', 3),
  (25, 3, 'Lead Generation & Qualification', 'Systematic generation of qualified leads through inbound and outbound channels.', '1.0', 4),
  (26, 3, 'Sales Enablement', 'Tools, content, training, and playbooks that equip the sales team to sell effectively.', '1.0', 5),
  (27, 3, 'Customer Onboarding', 'Structured process to transition new customers from sale to active, successful usage.', '1.0', 6),
  (28, 3, 'Account Management & Expansion', 'Proactive management of existing accounts to maximize retention, satisfaction, and expansion revenue.', '1.0', 7),
  (29, 3, 'Channel & Partnership Strategy', 'Identification and management of indirect sales channels and strategic partnerships.', '1.0', 8),
  (30, 3, 'Sales Compensation & Incentives', 'Compensation structures aligned with company goals that motivate desired selling behaviors.', '1.0', 9),
  (31, 3, 'CRM & Sales Technology Stack', 'Effective use of CRM and sales tools to track activity, manage relationships, and report performance.', '1.0', 10),
  (32, 4, 'Brand Positioning & Messaging', 'Clear, differentiated brand positioning with consistent messaging across all channels.', '1.0', 1),
  (33, 4, 'Demand Generation Strategy', 'Integrated approach to generating awareness and qualified demand through multiple channels.', '1.0', 2),
  (34, 4, 'Content Strategy & Production', 'Planned, consistent creation of valuable content that serves audience needs and business goals.', '1.0', 3),
  (35, 4, 'Digital Marketing Operations', 'Efficient execution of digital marketing campaigns including SEO, SEM, email, and social.', '1.0', 4),
  (36, 4, 'Marketing Analytics & Attribution', 'Measurement of marketing effectiveness with clear attribution of spend to pipeline and revenue.', '1.0', 5),
  (37, 4, 'Customer Advocacy & Referrals', 'Programs that turn satisfied customers into advocates who generate referrals and social proof.', '1.0', 6),
  (38, 4, 'Market Research & Segmentation', 'Ongoing research into market dynamics, customer segments, and emerging opportunities.', '1.0', 7),
  (39, 4, 'Marketing Technology Stack', 'Effective use of marketing automation, analytics, and campaign management tools.', '1.0', 8),
  (40, 4, 'Public Relations & Communications', 'Strategic management of public perception, media relations, and crisis communications.', '1.0', 9),
  (41, 4, 'Event & Community Strategy', 'Engagement with target audiences through events, communities, and experiential marketing.', '1.0', 10),
  (42, 5, 'Talent Acquisition & Recruiting', 'Ability to attract, evaluate, and hire the right talent at the pace the business requires.', '1.0', 1),
  (43, 5, 'Onboarding & Ramp-Up', 'Structured process to bring new hires to full productivity with clear milestones and support.', '1.0', 2),
  (44, 5, 'Performance Management', 'Regular, constructive performance evaluation and feedback cycles that drive improvement.', '1.0', 3),
  (45, 5, 'Compensation & Benefits', 'Competitive, equitable compensation structure that attracts and retains talent.', '1.0', 4),
  (46, 5, 'Culture & Values Alignment', 'Explicitly defined and actively maintained culture that guides behavior and decision-making.', '1.0', 5),
  (47, 5, 'Learning & Development', 'Investment in employee growth through training, mentoring, and career development paths.', '1.0', 6),
  (48, 5, 'Organizational Design', 'Structure, roles, and reporting lines aligned with strategy and scaled appropriately for stage.', '1.0', 7),
  (49, 5, 'Employee Engagement & Retention', 'Active measurement and improvement of employee satisfaction, engagement, and retention.', '1.0', 8),
  (50, 5, 'Succession Planning', 'Identification and development of future leaders for critical roles.', '1.0', 9),
  (51, 5, 'Diversity, Equity & Inclusion', 'Intentional practices to build a diverse, equitable, and inclusive workplace.', '1.0', 10),
  (52, 6, 'Architecture & Technical Design', 'Intentional system architecture that supports current needs and anticipated scale.', '1.0', 1),
  (53, 6, 'Engineering Standards & Practices', 'Coding standards, review processes, and engineering practices that ensure quality and consistency.', '1.0', 2),
  (54, 6, 'Technical Debt Management', 'Systematic identification, tracking, and reduction of technical debt.', '1.0', 3),
  (55, 6, 'Security & Compliance', 'Proactive security practices, vulnerability management, and regulatory compliance.', '1.0', 4),
  (56, 6, 'Infrastructure & Scalability', 'Reliable, scalable infrastructure that supports business growth without performance degradation.', '1.0', 5),
  (57, 6, 'CI/CD & Deployment Practices', 'Automated build, test, and deployment pipelines that enable frequent, reliable releases.', '1.0', 6),
  (58, 6, 'Monitoring & Observability', 'Comprehensive monitoring, logging, and alerting that enables rapid detection and resolution of issues.', '1.0', 7),
  (59, 6, 'Data Architecture & Management', 'Structured approach to data storage, access, quality, and governance.', '1.0', 8),
  (60, 6, 'API Strategy & Integration', 'Well-designed APIs and integration patterns that enable internal and external connectivity.', '1.0', 9),
  (61, 6, 'Technology Vendor Management', 'Strategic selection, management, and evaluation of technology vendors and platforms.', '1.0', 10),
  (62, 6, 'Disaster Recovery & Business Continuity', 'Tested plans and procedures for maintaining operations during and after disruptive events.', '1.0', 11),
  (63, 7, 'Project Delivery Methodology', 'Consistent, appropriate methodology for planning and delivering projects on time and within scope.', '1.0', 1),
  (64, 7, 'Resource Planning & Allocation', 'Effective matching of available resources to project and operational demands.', '1.0', 2),
  (65, 7, 'Quality Assurance & Testing', 'Systematic testing and quality verification processes that catch defects before customers do.', '1.0', 3),
  (66, 7, 'Process Documentation & Standardization', 'Documented, standardized processes for repeatable operations.', '1.0', 4),
  (67, 7, 'Operational Efficiency & Automation', 'Identification and elimination of waste through process improvement and automation.', '1.0', 5),
  (68, 7, 'Service Level Management', 'Defined, measured, and managed service levels for internal and external customers.', '1.0', 6),
  (69, 7, 'Incident Management', 'Structured response to incidents with root cause analysis and prevention of recurrence.', '1.0', 7),
  (70, 7, 'Change Management', 'Controlled process for introducing changes to minimize disruption and risk.', '1.0', 8),
  (71, 7, 'Customer Support Operations', 'Efficient, high-quality customer support with clear escalation paths and resolution tracking.', '1.0', 9),
  (72, 7, 'Supply Chain & Vendor Operations', 'Management of external suppliers and operational dependencies for reliability and cost.', '1.0', 10),
  (73, 8, 'Strategic Planning Process', 'Regular, structured strategic planning that aligns the organization around shared goals and priorities.', '1.0', 1),
  (74, 8, 'Decision-Making Framework', 'Clear, documented frameworks for how decisions are made, by whom, and with what inputs.', '1.0', 2),
  (75, 8, 'Board & Advisor Management', 'Effective management of board relationships, reporting, and advisory input.', '1.0', 3),
  (76, 8, 'Risk Management & Mitigation', 'Proactive identification, assessment, and mitigation of business risks.', '1.0', 4),
  (77, 8, 'Executive Team Alignment', 'Cohesive executive team with shared understanding of strategy, roles, and accountability.', '1.0', 5),
  (78, 8, 'Meeting Cadence & Governance Rhythms', 'Structured meeting cadences (weekly, monthly, quarterly) that maintain alignment and momentum.', '1.0', 6),
  (79, 8, 'Delegation & Authority Matrix', 'Clear delegation of authority with defined decision rights at each organizational level.', '1.0', 7),
  (80, 8, 'OKR & Goal Setting', 'Objectives and key results or equivalent goal framework that cascades from strategy to execution.', '1.0', 8),
  (81, 8, 'Legal & Regulatory Compliance', 'Proactive management of legal obligations, contracts, and regulatory requirements.', '1.0', 9),
  (82, 8, 'Stakeholder Communication & Transparency', 'Regular, transparent communication with all stakeholders including employees, investors, and partners.', '1.0', 10);
