INSERT INTO maturity_levels (practice_id, level, descriptor, evidence_criteria, expiry_period_days) VALUES
  (1, 1, 'No documented revenue model; pricing is ad hoc or undefined', 'No written revenue model exists; pricing decisions made case-by-case', NULL),
  (1, 2, 'Basic revenue model articulated but not validated or consistently applied', 'Written revenue model document exists; at least one pricing tier defined', NULL),
  (1, 3, 'Revenue model documented with clear pricing tiers and monetization strategy', 'Revenue model document with pricing tiers, value metrics, and monetization logic reviewed within last 12 months', 365),
  (1, 4, 'Revenue model actively tested and optimized with data-driven pricing experiments', 'Evidence of pricing experiments or A/B tests; revenue model review cadence with results tracked; unit economics per tier documented', 365),
  (1, 5, 'Revenue model continuously refined with predictive analytics and market-leading pricing innovation', 'Predictive revenue modeling in place; dynamic pricing or value-based pricing fully implemented; quarterly model review with board-level reporting', 180),
  (2, 1, 'Unit economics not tracked; no visibility into CAC, LTV, or margins', 'No unit economics dashboard or calculations exist', NULL),
  (2, 2, 'Basic unit economics calculated periodically but not systematically tracked', 'CAC and LTV calculated at least once; basic spreadsheet or document exists', NULL),
  (2, 3, 'Unit economics tracked monthly with defined CAC, LTV, and contribution margin metrics', 'Monthly unit economics report or dashboard; CAC, LTV, gross margin, and contribution margin all tracked; definitions documented', 365),
  (2, 4, 'Unit economics integrated into decision-making with cohort analysis and segment-level tracking', 'Cohort-based LTV analysis; segment-level CAC tracking; unit economics influence product and marketing decisions with documented examples', 365),
  (2, 5, 'Predictive unit economics with real-time dashboards and automated alerting on margin shifts', 'Real-time unit economics dashboard; predictive models for LTV and CAC; automated alerts on metric degradation; quarterly optimization reviews', 180),
  (3, 1, 'Cash flow not forecasted; reactive management of cash position', 'No cash flow forecast exists; bank balance checked ad hoc', NULL),
  (3, 2, 'Basic cash flow tracking with simple short-term forecasting', 'Monthly cash flow statement produced; basic 30-day forecast exists', NULL),
  (3, 3, 'Regular cash flow forecasting with 90-day rolling projections and variance tracking', '90-day rolling cash flow forecast updated at least bi-weekly; variance analysis performed monthly; AR/AP aging tracked', 365),
  (3, 4, 'Proactive cash flow optimization with scenario modeling and working capital management', 'Scenario-based cash flow models (best/worst/expected); working capital optimization initiatives documented; cash conversion cycle tracked', 365),
  (3, 5, 'Automated cash flow management with real-time visibility and predictive treasury operations', 'Real-time cash position dashboard; automated cash flow forecasting with ML-driven predictions; treasury policy documented and reviewed quarterly', 180),
  (4, 1, 'No formal budgeting or financial planning process', 'No annual budget or financial plan exists', NULL),
  (4, 2, 'Annual budget created but rarely updated; limited variance analysis', 'Annual budget document exists; some comparison of actual vs. budget performed', NULL),
  (4, 3, 'Quarterly financial planning with monthly variance analysis and basic scenario planning', 'Quarterly reforecast process documented; monthly variance reports with explanations; at least two scenarios modeled annually', 365),
  (4, 4, 'Integrated FP&A with driver-based models, rolling forecasts, and cross-functional input', 'Driver-based financial model; rolling 12-month forecast; cross-functional planning inputs documented; FP&A calendar with stakeholder sign-off', 365),
  (4, 5, 'Continuous planning with real-time data integration, automated reporting, and strategic scenario analysis', 'Real-time financial dashboards; automated variance detection; strategic scenario planning tied to board reporting; FP&A team with dedicated tooling', 180),
  (5, 1, 'Pricing set intuitively with no market or cost analysis', 'No pricing analysis or documentation exists; prices set by founder intuition', NULL),
  (5, 2, 'Basic pricing established with some competitor or cost-based analysis', 'Competitor pricing comparison exists; cost-plus or simple markup logic documented', NULL),
  (5, 3, 'Pricing strategy documented with market positioning rationale and regular review cadence', 'Pricing strategy document with positioning rationale; annual pricing review process; customer willingness-to-pay data collected', 365),
  (5, 4, 'Data-driven pricing optimization with segmented pricing and elasticity analysis', 'Price elasticity analysis performed; segment-specific pricing tiers; pricing experiments documented with results; pricing committee or owner defined', 365),
  (5, 5, 'Dynamic, value-based pricing with continuous optimization and competitive moat', 'Value-based pricing methodology implemented; dynamic pricing or usage-based models with real-time adjustment; quarterly pricing optimization reviews with revenue impact analysis', 180),
  (6, 1, 'No visibility into cost structure; spending decisions made without analysis', 'No cost breakdown or analysis exists', NULL),
  (6, 2, 'Basic cost categories identified; some awareness of major cost drivers', 'Cost categories documented; major cost drivers identified in at least one review', NULL),
  (6, 3, 'Cost structure documented with regular reviews and identified optimization opportunities', 'Cost structure breakdown by category; quarterly cost reviews; at least two optimization initiatives identified and tracked', 365),
  (6, 4, 'Proactive cost management with benchmarking, vendor negotiations, and efficiency targets', 'Industry benchmarking data used; vendor renegotiation cadence documented; efficiency targets set and tracked; cost per unit metrics monitored', 365),
  (6, 5, 'Continuous cost optimization with automated monitoring and zero-based budgeting practices', 'Automated cost monitoring with anomaly alerts; zero-based or activity-based costing implemented; cost optimization tied to strategic planning; quarterly efficiency gains reported', 180),
  (7, 1, 'Single revenue stream with high concentration risk', 'Revenue from one product/service or one major customer exceeds 80%', NULL),
  (7, 2, 'Awareness of concentration risk; initial exploration of additional revenue streams', 'Concentration risk acknowledged in planning documents; at least one new revenue stream being explored', NULL),
  (7, 3, 'Two or more revenue streams contributing meaningfully; diversification strategy documented', 'At least two revenue streams each contributing >10% of revenue; diversification strategy documented with targets', 365),
  (7, 4, 'Multiple revenue streams actively managed with segment-level P&L and portfolio approach', 'Three or more revenue streams; segment-level P&L tracking; portfolio-level revenue management with investment allocation rationale', 365),
  (7, 5, 'Balanced revenue portfolio with systematic new-stream incubation and no single-source dependency', 'No single revenue stream exceeds 40%; systematic new revenue stream incubation process; quarterly portfolio rebalancing reviews; geographic or market diversification', 180),
  (8, 1, 'Financial reporting is informal, late, or inaccurate; no internal controls', 'No regular financial reports produced; no documented controls or processes', NULL),
  (8, 2, 'Basic financial reports produced but often late or incomplete; minimal controls', 'Monthly financial statements produced (even if delayed); basic bank reconciliation performed', NULL),
  (8, 3, 'Timely monthly financial reporting with documented controls and reconciliation processes', 'Monthly close within 15 business days; documented accounting policies; bank and key account reconciliations performed monthly; chart of accounts defined', 365),
  (8, 4, 'Comprehensive reporting with segregation of duties, audit-ready processes, and management dashboards', 'Monthly close within 10 business days; segregation of duties documented; annual audit completed; management dashboard with KPIs; internal control matrix documented', 365),
  (8, 5, 'Real-time financial reporting with automated controls, continuous auditing, and board-ready packages', 'Monthly close within 5 business days; automated control testing; continuous auditing processes; board-ready financial packages; SOX-equivalent controls or SOC 2 compliance', 180),
  (9, 1, 'Capital allocation decisions made ad hoc without framework or criteria', 'No capital allocation framework; investment decisions made by intuition or urgency', NULL),
  (9, 2, 'Basic awareness of capital allocation; some prioritization of spending', 'Annual budget allocates capital to categories; some discussion of ROI before major investments', NULL),
  (9, 3, 'Capital allocation framework with defined criteria and regular review of investment performance', 'Written capital allocation criteria (ROI thresholds, strategic fit); quarterly investment reviews; portfolio of investments tracked with expected vs. actual returns', 365),
  (9, 4, 'Disciplined capital allocation with portfolio optimization, hurdle rates, and stage-gate governance', 'Defined hurdle rates by investment type; stage-gate process for large investments; portfolio view of all capital commitments; post-investment reviews documented', 365),
  (9, 5, 'Strategic capital allocation with real-option thinking, dynamic rebalancing, and value-creation tracking', 'Real-option or DCF analysis for major investments; dynamic portfolio rebalancing process; value-creation tracking against strategic plan; board-level capital allocation review quarterly', 180),
  (10, 1, 'No structured investor or stakeholder communication; updates are reactive', 'No regular investor updates; communication happens only when investors ask', NULL),
  (10, 2, 'Periodic investor updates sent but inconsistent in format and cadence', 'At least quarterly investor updates sent; basic financial summary included', NULL),
  (10, 3, 'Regular, structured investor communication with consistent reporting and proactive updates', 'Monthly or quarterly investor report template; proactive communication of material events; KPI dashboard shared with investors; stakeholder list maintained', 365),
  (10, 4, 'Strategic stakeholder management with tailored communication, board materials, and relationship tracking', 'Board materials prepared with strategic context; stakeholder-specific communication plans; investor CRM or tracking system; annual investor day or strategic review', 365),
  (10, 5, 'Best-in-class investor relations with proactive narrative management and institutional-grade reporting', 'Institutional-grade reporting package; proactive IR strategy with media coordination; benchmarking against public-company IR standards; NPS or satisfaction survey from stakeholders', 180),
  (11, 1, 'No documented product vision; direction changes frequently', 'No written product vision or strategy document exists', NULL),
  (11, 2, 'Basic product vision exists but not widely shared or used to guide decisions', 'Product vision statement written; some team members aware of it', NULL),
  (11, 3, 'Clear product vision documented and shared with the team; strategy tied to business goals', 'Product vision and strategy document reviewed within 12 months; team can articulate the vision; strategy linked to business objectives', 365),
  (11, 4, 'Product vision drives roadmap decisions with measurable strategic outcomes and regular validation', 'Vision-to-roadmap traceability documented; strategic outcomes measured quarterly; vision validated with customer and market data; cross-functional alignment sessions held', 365),
  (11, 5, 'Inspiring product vision that drives company strategy with continuous market validation and thought leadership', 'Product vision influences company-level strategy; continuous market validation loop; thought leadership content published; annual vision refresh with board input', 180),
  (12, 1, 'No systematic customer research; assumptions drive product decisions', 'No customer interviews, surveys, or research conducted in the last 6 months', NULL),
  (12, 2, 'Some customer conversations happen but informally and without consistent methodology', 'At least some customer interviews conducted; informal notes or summaries exist', NULL),
  (12, 3, 'Regular customer discovery with documented methodology and synthesis of insights', 'Customer interview process documented; at least 10 interviews per quarter; insight synthesis shared with product team; personas or JTBD documented', 365),
  (12, 4, 'Continuous customer discovery integrated into product development with cross-functional participation', 'Engineers and designers participate in customer research; research repository maintained; insights directly influence roadmap with documented examples; discovery sprints scheduled', 365),
  (12, 5, 'Customer-obsessed discovery process with predictive insights, ethnographic research, and market-shaping innovation', 'Ethnographic or contextual inquiry methods used; predictive customer need analysis; customer advisory board active; research influences strategic direction beyond product', 180),
  (13, 1, 'No product roadmap; work is decided week to week', 'No roadmap document or tool exists; priorities shift constantly', NULL),
  (13, 2, 'Basic roadmap exists as a feature list but lacks strategic framing or timeline', 'A list of planned features or projects exists; some rough sequencing defined', NULL),
  (13, 3, 'Outcome-driven roadmap with clear themes, time horizons, and stakeholder communication', 'Roadmap organized by themes or outcomes; now/next/later or quarterly time horizons; roadmap shared with stakeholders regularly; linked to product strategy', 365),
  (13, 4, 'Dynamic roadmap with data-driven prioritization, capacity planning, and cross-functional input', 'Roadmap updated based on data and customer feedback; capacity planning integrated; cross-functional input process documented; roadmap review cadence established with leadership', 365),
  (13, 5, 'Continuously optimized roadmap with OKR alignment, predictive planning, and portfolio-level management', 'Roadmap tied to OKRs with measurable outcomes; predictive capacity and impact modeling; multi-product portfolio roadmap management; quarterly roadmap retrospectives', 180),
  (14, 1, 'Features prioritized by loudest voice or founder preference', 'No prioritization framework; decisions made ad hoc by HiPPO', NULL),
  (14, 2, 'Some prioritization criteria discussed but not consistently applied', 'Team has discussed prioritization approaches; some use of impact/effort or similar heuristics', NULL),
  (14, 3, 'Defined prioritization framework applied consistently with documented decision rationale', 'Prioritization framework documented (RICE, ICE, weighted scoring, or equivalent); applied to last 3+ prioritization decisions with rationale recorded', 365),
  (14, 4, 'Data-driven prioritization with quantified impact, opportunity cost analysis, and stakeholder alignment', 'Quantified impact estimates for prioritized features; opportunity cost considered; stakeholder input process defined; prioritization decisions reviewed for accuracy retroactively', 365),
